import{_ as a,o as s,c as t,a2 as e}from"./chunks/framework.BRk9mohw.js";const u=JSON.parse('{"title":"Nano Banana Pro 图像生成与编辑","description":"","frontmatter":{"名称":"nano-banana-pro","描述":"使用 Nano Banana Pro（Gemini 3 Pro Image）生成/编辑图像。用于图像创建/修改请求，包括编辑。支持文本到图像 + 图像到图像；1K/2K/4K；使用 --input-image。"},"headers":[],"relativePath":"skills/nano-banana-pro.md","filePath":"skills/nano-banana-pro.md"}'),l={name:"skills/nano-banana-pro.md"};function n(o,i,p,h,r,d){return s(),t("div",null,[...i[0]||(i[0]=[e('<h1 id="nano-banana-pro-图像生成与编辑" tabindex="-1">Nano Banana Pro 图像生成与编辑 <a class="header-anchor" href="#nano-banana-pro-图像生成与编辑" aria-label="Permalink to &quot;Nano Banana Pro 图像生成与编辑&quot;">​</a></h1><p>使用 Google 的 Nano Banana Pro API（Gemini 3 Pro Image）生成新图像或编辑现有图像。</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><p>使用绝对路径运行脚本（不要先 cd 到技能目录）：</p><p><strong>生成新图像：</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codex/skills/nano-banana-pro/scripts/generate_image.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --prompt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;您的图像描述&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filename</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;output-name.png&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--resolution </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1K</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">2K</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">4K]</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--api-key </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">KEY]</span></span></code></pre></div><p><strong>编辑现有图像：</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codex/skills/nano-banana-pro/scripts/generate_image.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --prompt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;编辑指令&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filename</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;output-name.png&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --input-image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;path/to/input.png&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--resolution </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1K</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">2K</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">4K]</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--api-key </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">KEY]</span></span></code></pre></div><p>**重要：**始终从用户的当前工作目录运行，这样图像会保存在用户正在工作的位置，而不是技能目录中。</p><h2 id="默认工作流-草稿-→-迭代-→-定稿" tabindex="-1">默认工作流（草稿 → 迭代 → 定稿） <a class="header-anchor" href="#默认工作流-草稿-→-迭代-→-定稿" aria-label="Permalink to &quot;默认工作流（草稿 → 迭代 → 定稿）&quot;">​</a></h2><p>目标：在提示正确之前快速迭代，避免在 4K 上浪费时间。</p><ul><li>草稿（1K）：快速反馈循环 <ul><li><code>uv run ~/.codex/skills/nano-banana-pro/scripts/generate_image.py --prompt &quot;&lt;草稿提示&gt;&quot; --filename &quot;yyyy-mm-dd-hh-mm-ss-draft.png&quot; --resolution 1K</code></li></ul></li><li>迭代：小幅调整提示；每次运行保持文件名新颖 <ul><li>如果是编辑：保持相同的 <code>--input-image</code> 进行每次迭代，直到满意为止。</li></ul></li><li>定稿（4K）：仅当提示确定后 <ul><li><code>uv run ~/.codex/skills/nano-banana-pro/scripts/generate_image.py --prompt &quot;&lt;最终提示&gt;&quot; --filename &quot;yyyy-mm-dd-hh-mm-ss-final.png&quot; --resolution 4K</code></li></ul></li></ul><h2 id="分辨率选项" tabindex="-1">分辨率选项 <a class="header-anchor" href="#分辨率选项" aria-label="Permalink to &quot;分辨率选项&quot;">​</a></h2><p>Gemini 3 Pro Image API 支持三种分辨率（需要大写 K）：</p><ul><li><strong>1K</strong>（默认）- 约 1024px 分辨率</li><li><strong>2K</strong> - 约 2048px 分辨率</li><li><strong>4K</strong> - 约 4096px 分辨率</li></ul><p>将用户请求映射到 API 参数：</p><ul><li>未提及分辨率 → <code>1K</code></li><li>&quot;低分辨率&quot;、&quot;1080&quot;、&quot;1080p&quot;、&quot;1K&quot; → <code>1K</code></li><li>&quot;2K&quot;、&quot;2048&quot;、&quot;正常&quot;、&quot;中等分辨率&quot; → <code>2K</code></li><li>&quot;高分辨率&quot;、&quot;高解析度&quot;、&quot;hi-res&quot;、&quot;4K&quot;、&quot;超高清&quot; → <code>4K</code></li></ul><h2 id="api-密钥" tabindex="-1">API 密钥 <a class="header-anchor" href="#api-密钥" aria-label="Permalink to &quot;API 密钥&quot;">​</a></h2><p>脚本按以下顺序检查 API 密钥：</p><ol><li><code>--api-key</code> 参数（如果在聊天中提供了密钥）</li><li><code>GEMINI_API_KEY</code> 环境变量</li></ol><p>如果两者都不可用，脚本将退出并显示错误消息。</p><h2 id="预检-常见失败-快速修复" tabindex="-1">预检 + 常见失败（快速修复） <a class="header-anchor" href="#预检-常见失败-快速修复" aria-label="Permalink to &quot;预检 + 常见失败（快速修复）&quot;">​</a></h2><ul><li><p>预检：</p><ul><li><code>command -v uv</code>（必须存在）</li><li><code>test -n &quot;$GEMINI_API_KEY&quot;</code>（或传递 <code>--api-key</code>）</li><li>如果是编辑：<code>test -f &quot;path/to/input.png&quot;</code></li></ul></li><li><p>常见失败：</p><ul><li><code>Error: No API key provided.</code> → 设置 <code>GEMINI_API_KEY</code> 或传递 <code>--api-key</code></li><li><code>Error loading input image:</code> → 路径错误/文件不可读；验证 <code>--input-image</code> 指向真实的图像</li><li>&quot;quota/permission/403&quot; 风格的 API 错误 → 密钥错误、无访问权限或配额超出；尝试不同的密钥/账户</li></ul></li></ul><h2 id="文件名生成" tabindex="-1">文件名生成 <a class="header-anchor" href="#文件名生成" aria-label="Permalink to &quot;文件名生成&quot;">​</a></h2><p>使用模式生成文件名：<code>yyyy-mm-dd-hh-mm-ss-name.png</code></p><p><strong>格式：</strong><code>{时间戳}-{描述性名称}.png</code></p><ul><li>时间戳：当前日期/时间，格式为 <code>yyyy-mm-dd-hh-mm-ss</code>（24 小时制）</li><li>名称：描述性的小写文本，用连字符</li><li>保持描述部分简洁（通常 1-5 个词）</li><li>使用用户提示或对话中的上下文</li><li>如果不清楚，使用随机标识符（例如 <code>x9k2</code>、<code>a7b3</code>）</li></ul><p>示例：</p><ul><li>提示 &quot;A serene Japanese garden&quot; → <code>2025-11-23-14-23-05-japanese-garden.png</code></li><li>提示 &quot;sunset over mountains&quot; → <code>2025-11-23-15-30-12-sunset-mountains.png</code></li><li>提示 &quot;create an image of a robot&quot; → <code>2025-11-23-16-45-33-robot.png</code></li><li>上下文不清楚 → <code>2025-11-23-17-12-48-x9k2.png</code></li></ul><h2 id="图像编辑" tabindex="-1">图像编辑 <a class="header-anchor" href="#图像编辑" aria-label="Permalink to &quot;图像编辑&quot;">​</a></h2><p>当用户想要修改现有图像时：</p><ol><li>检查他们是否提供了图像路径或引用了当前目录中的图像</li><li>使用 <code>--input-image</code> 参数并提供图像路径</li><li>提示应包含编辑指令（例如 &quot;让天空更戏剧化&quot;、&quot;移除人物&quot;、&quot;改为卡通风格&quot;）</li><li>常见编辑任务：添加/删除元素、更改风格、调整颜色、模糊背景等</li></ol><h2 id="提示处理" tabindex="-1">提示处理 <a class="header-anchor" href="#提示处理" aria-label="Permalink to &quot;提示处理&quot;">​</a></h2><p>**对于生成：**直接将用户的图像描述传递给 <code>--prompt</code>。只有明显不足时才重新修改。</p><p>**对于编辑：**在 <code>--prompt</code> 中传递编辑指令（例如 &quot;在天空中添加彩虹&quot;、&quot;让它看起来像水彩画&quot;）</p><p>在两种情况下都保留用户的创意意图。</p><h2 id="高命中率的提示模板" tabindex="-1">高命中率的提示模板 <a class="header-anchor" href="#高命中率的提示模板" aria-label="Permalink to &quot;高命中率的提示模板&quot;">​</a></h2><p>当用户表达模糊或编辑必须精确时使用模板。</p><ul><li><p>生成模板：</p><ul><li>&quot;创建图像：&lt;主体&gt;。风格：&lt;风格&gt;。构图：&lt;相机/镜头&gt;。光线：&lt;光线&gt;。背景：&lt;背景&gt;。配色：&lt;调色板&gt;。避免：&lt;列表&gt;。&quot;</li></ul></li><li><p>编辑模板（保留其他所有内容）：</p><ul><li>&quot;仅更改：&lt;单一更改&gt;。保持不变：主体、构图/裁剪、姿势、光线、配色、背景、文本和整体风格。不要添加新对象。如果存在文本，保持不变。&quot;</li></ul></li></ul><h2 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h2><ul><li>将 PNG 保存到当前目录（如果文件名包含目录，则保存到指定路径）</li><li>脚本输出生成的图像的完整路径</li><li><strong>不要回读图像</strong> - 只告知用户保存的路径</li></ul><h2 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h2><p><strong>生成新图像：</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codex/skills/nano-banana-pro/scripts/generate_image.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --prompt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;A serene Japanese garden with cherry blossoms&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filename</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2025-11-23-14-23-05-japanese-garden.png&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --resolution</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 4K</span></span></code></pre></div><p><strong>编辑现有图像：</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codex/skills/nano-banana-pro/scripts/generate_image.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --prompt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;make the sky more dramatic with storm clouds&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filename</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;2025-11-23-14-25-30-dramatic-sky.png&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --input-image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;original-photo.jpg&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --resolution</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 2K</span></span></code></pre></div>',46)])])}const c=a(l,[["render",n]]);export{u as __pageData,c as default};
